    Component({
        selector: 'pf-card',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `<ng-content></ng-content>`,
        host: {
            '[class]': 'classes',
        },
    })
], PfCardComponent);
export { PfCardComponent };
let PfCardHeaderComponent = class PfCardHeaderComponent {
    constructor() {
        this.title = '';
        this.subtitle = '';
    }
    static { this.propDecorators = {
        title: [{ type: Input }],
        subtitle: [{ type: Input }]
    }; }
};
PfCardHeaderComponent = __decorate([
    Component({
        selector: 'pf-card-header',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    @if (title) {
      <h3 class="ds-card__title">{{ title }}</h3>
    }
    @if (subtitle) {
      <p class="ds-card__subtitle">{{ subtitle }}</p>
    }
    <ng-content></ng-content>
  `,
        host: { class: 'ds-card__header' },
    })
], PfCardHeaderComponent);
export { PfCardHeaderComponent };
let PfCardBodyComponent = class PfCardBodyComponent {
};
PfCardBodyComponent = __decorate([
    Component({
        selector: 'pf-card-body',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `<ng-content></ng-content>`,
        host: { class: 'ds-card__body' },
    })
], PfCardBodyComponent);
export { PfCardBodyComponent };
let PfCardFooterComponent = class PfCardFooterComponent {
};
